/* eslint-disable no-undef */
import { precacheAndRoute } from 'workbox-precaching';

// Precache all of the assets generated by your build process.
// Their URLs are injected into the manifest variable below.
// This variable must be present somewhere in your service worker file,
// even if you decide not to use precaching. See https://cra.link/PWA
precacheAndRoute(self.__WB_MANIFEST || []);

import { initializeApp } from 'firebase/app';
import { getMessaging, onBackgroundMessage } from 'firebase/messaging/sw';

// Initialize the Firebase app in the service worker
const firebaseConfig = {
    apiKey: "AIzaSyDI1FYcK64boB-ClbfFeuJmzab-94wnl3s",
    authDomain: "news-9d3d2.firebaseapp.com",
    projectId: "news-9d3d2",
    storageBucket: "news-9d3d2.firebasestorage.app",
    messagingSenderId: "902407030535",
    appId: "1:902407030535:web:cbb9c9a7fe5c745f4d27a2"
};

const app = initializeApp(firebaseConfig);
const messaging = getMessaging(app);

self.addEventListener('install', (event) => {
    console.log('[sw.js] Installing new version...');
    self.skipWaiting(); // Force this SW to become the active one
});

self.addEventListener('activate', (event) => {
    console.log('[sw.js] Activated. Claiming clients...');
    event.waitUntil(clients.claim()); // Take control of all open pages immediately
});

// Handle standard Web Push (from our Node backend)
self.addEventListener('push', (event) => {
    console.log('[sw.js] Push received', event);
    let data = {};
    if (event.data) {
        try {
            data = event.data.json();
        } catch (e) {
            console.log('[sw.js] Push data is not JSON', event.data.text());
            data = { body: event.data.text() };
        }
    }

    const title = data.title || 'BudgetWise Notification';
    const options = {
        body: data.body || 'New notification',
        icon: data.icon || '/logo.svg',
        badge: data.badge || '/logo.svg',
        tag: data.tag || 'general-notification',
        data: data.data || { url: '/' },
        requireInteraction: true,
        renotify: true,
        vibrate: [200, 100, 200]
    };

    event.waitUntil(
        self.registration.showNotification(title, options)
    );
});

// Handle Firebase background messages (keep as fallback/legacy)
try {
    onBackgroundMessage(messaging, (payload) => {
        console.log('[sw.js] Received background message ', payload);
        const notificationTitle = payload.notification.title;
        const notificationOptions = {
            body: payload.notification.body,
            icon: '/logo.svg',
            badge: '/logo.svg'
        };

        self.registration.showNotification(notificationTitle, notificationOptions);
    });
} catch (err) {
    console.warn('Firebase Messaging not supported in SW (probably http):', err);
}

self.addEventListener('notificationclick', (event) => {
    console.log('[sw.js] Notification clicked', event.notification.tag);
    event.notification.close();

    // URL to open
    const targetUrl = event.notification.data ? event.notification.data.url : '/';

    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then(windowClients => {
            // Check if there is already a window/tab open with the target URL
            for (var i = 0; i < windowClients.length; i++) {
                var client = windowClients[i];
                if (client.url === targetUrl && 'focus' in client) {
                    return client.focus();
                }
            }
            if (clients.openWindow) {
                return clients.openWindow(targetUrl);
            }
        })
    );
});
